// Parse the scheduler output
const output = $json.stdout || '';
const lines = output.split('\n');

// Extract key information from logs
let queuedCount = 0;
let totalQueued = 0;
let currentIndex = 0;
let status = {};

for (const line of lines) {
  if (line.includes('Added') && line.includes('books to queue')) {
    const match = line.match(/Added (\d+) books to queue/);
    if (match) queuedCount = parseInt(match[1]);
  }
  if (line.includes('Config saved')) {
    const indexMatch = line.match(/index=(\d+)/);
    const totalMatch = line.match(/total_queued=(\d+)/);
    if (indexMatch) currentIndex = parseInt(indexMatch[1]);
    if (totalMatch) totalQueued = parseInt(totalMatch[1]);
  }
  if (line.includes('Queue Status')) {
    const pendingMatch = line.match(/(\d+) pending/);
    const acquiredMatch = line.match(/(\d+) acquired/);
    const totalMatch = line.match(/(\d+) total/);
    if (pendingMatch) status.pending = parseInt(pendingMatch[1]);
    if (acquiredMatch) status.acquired = parseInt(acquiredMatch[1]);
    if (totalMatch) status.total = parseInt(totalMatch[1]);
  }
}

return {json: {
  queued: queuedCount,
  total_queued_session: totalQueued,
  current_index: currentIndex,
  status: status,
  success: queuedCount > 0,
  timestamp: new Date().toISOString(),
  raw_output: output
}};

// Build Discord message with status
const queued = $json.queued || 0;
const pending = $json.status?.pending || 0;
const acquired = $json.status?.acquired || 0;
const total = $json.status?.total || 0;
const index = $json.current_index || 0;

let color = 5793266; // Default blue
let emoji = '📚';

if (queued === 0) {
  emoji = '✅';
  color = 3066993; // Green - all canon queued
}

const progressPercent = index > 0 ? Math.round((index / 251) * 100) : 0;
const progressBar = '█'.repeat(Math.floor(progressPercent / 5)) + '░'.repeat(20 - Math.floor(progressPercent / 5));

return {json: {
  embeds: [{
    title: `${emoji} Canon Hourly Queue Update`,
    fields: [
      {
        name: 'Books Added This Hour',
        value: `**${queued}** books queued`,
        inline: true
      },
      {
        name: 'Progress',
        value: `${index}/251 books (${progressPercent}%)`,
        inline: true
      },
      {
        name: 'Queue Status',
        value: `⏳ **${pending}** pending | ✅ **${acquired}** acquired`,
        inline: false
      },
      {
        name: 'Progress Bar',
        value: `\`${progressBar}\` ${progressPercent}%`,
        inline: false
      }
    ],
    color: color,
    timestamp: new Date().toISOString(),
    footer: {
      text: 'LIBRARIAN Canon Scheduler'
    }
  }],
  status: 'success'
}};
